// Route + Build Task v6 — updated for strategic discovery layer
// Scheduled runs: emit strategic_sweep = true → Strategic Discovery node handles multi-target logic
// Manual runs with explicit query: single-target mode (bypasses strategic layer)
const raw = $input.first().json;
const body = raw.body || raw;
const isScheduled = !body.query && !body.command;
const query = String(body.query || body.command || '');

// Manual single-target run: pass through directly to strategic discovery
// but mark as single-target so it generates exactly one opportunity
if (!isScheduled && query) {
  return [{ json: {
    mode: body.mode || 'bd',
    query,
    grantName: body.grantName || null,
    sourceLabel: 'Manual',
    isScheduled: false,
    strategic_sweep: false,
    single_query_override: query,
    timestamp: new Date().toISOString()
  }}];
}

// Scheduled run: build context for strategic discovery
const today = new Date();
const day = today.getDay();
const startOfYear = new Date(today.getFullYear(), 0, 1);
const weekNum = Math.ceil(((today - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const isWeekA = weekNum % 2 !== 0;

// Focus themes rotate by week/day — Strategic Discovery uses these as priming context
// not as fixed queries. The AI decides the actual searches.
const weekA_themes = {
  1: { primary: 'federal_compliance_consulting', secondary: 'cmmc_omb_m2602', mode: 'bd' },
