// ─────────────────────────────────────────────────────────────────────────────
const fs = require('fs');
const https = require('https');

const input = $input.first().json;
const { mode, isScheduled, strategic_sweep, single_query_override,
        theme_primary, theme_secondary, theme_mode, sourceLabel, timestamp } = input;

// ── Load KAI Context ─────────────────────────────────────────────────────────
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }

