}

// ── Build broad search queries for strategic sweep ───────────────────────────
// Run 3 parallel Brave searches across the landscape, then synthesize
const BRAVE_KEY = $env.BRAVE_API_KEY || '';

async function braveSearch(query, count = 5) {
  const path = `/res/v1/web/search?q=${encodeURIComponent(query)}&count=${count}&search_lang=en&country=us&text_decorations=false&extra_snippets=true`;
  return new Promise((resolve) => {
    const req = https.request({
      hostname: 'api.search.brave.com', port: 443, path, method: 'GET',
      headers: { 'Accept': 'application/json', 'X-Subscription-Token': BRAVE_KEY }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try {
          const parsed = JSON.parse(Buffer.concat(chunks).toString());
          const results = (parsed?.web?.results || []).slice(0, count).map(r => ({
            title: r.title || '',
            url: r.url || '',
            description: r.description || '',
            snippet: (r.extra_snippets || []).slice(0, 1).join(' ')
          }));
          resolve({ ok: true, query, results });
        } catch(e) { resolve({ ok: false, query, results: [], error: e.message }); }
      });
    });
    req.on('error', () => resolve({ ok: false, query, results: [] }));
    req.end();
  });
}

