// Execute all 3 Brave searches in parallel
const searchResults = await Promise.all(sweepQueries.map(q => braveSearch(q, 5)));

// Format search context for Claude strategic analysis
const searchContext = searchResults.map((sr, i) => {
  const resultText = sr.results.map((r, j) =>
    `[${i+1}.${j+1}] ${r.title}\nURL: ${r.url}\n${r.description}${r.snippet ? '\nDetail: ' + r.snippet : ''}`
  ).join('\n\n');
  return `=== SEARCH ${i+1}: ${sr.query} ===\n${resultText || '(no results)'}`;
}).join('\n\n');

// ── Strategic Discovery Claude call ───────────────────────────────────────────
const systemPrompt = `You are Scout, KAI-Netics Strategic Intelligence Director.

Your role: Survey the BD and grant landscape, think like an executive strategist, and identify the BEST 3-5 distinct actionable opportunities for KAI-Netics this week.

FOUNDER: ${founder.name || 'Kevin Alexander Smith'}
CREDENTIALS: ${credStack}
