    }
  ]
}`;

const userPrompt = `Today: ${new Date().toLocaleDateString('en-US', {weekday:'long', year:'numeric', month:'long', day:'numeric', timeZone:'America/New_York'})}
Theme focus: ${theme_primary} / ${theme_secondary || 'general'}

LIVE SEARCH DATA:
${searchContext}

Based on the live search data and KAI-Netics strategic context, identify the 3-5 best distinct opportunities to pursue this week. Think: what would a senior BD executive prioritize from this landscape for Kevin's specific credential stack and phase? Return strict JSON only.`;

const reqBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 3000,
  system: systemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
});

const claudeResult = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.anthropic.com', port: 443,
    path: '/v1/messages', method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': process.env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'Content-Length': Buffer.byteLength(reqBody)
    }
  }, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => resolve({ status: res.statusCode, body: d }));
  });
  req.on('error', reject);
  req.write(reqBody);
  req.end();
});

let discoveryResult = null;
try {
  const parsed = JSON.parse(claudeResult.body);
  const rawText = parsed?.content?.[0]?.text || '';
  const clean = rawText.replace(/^```json\s*/,'').replace(/^```\s*/,'').replace(/\s*```$/,'').trim();
  try { discoveryResult = JSON.parse(clean); }
  catch(e) {
    const first = clean.indexOf('{'); const last = clean.lastIndexOf('}');
    if (first !== -1 && last > first) discoveryResult = JSON.parse(clean.substring(first, last+1));
  }
} catch(e) { discoveryResult = null; }

// Fallback: if Claude parse fails, emit single opportunity from theme
if (!discoveryResult || !Array.isArray(discoveryResult.opportunities) || !discoveryResult.opportunities.length) {
  discoveryResult = {
    strategic_summary: `Strategic sweep fallback for theme: ${theme_primary}`,
    opportunities: [{
      rank: 1,
      opportunity_target: sweepQueries[0],
      search_query: sweepQueries[0],
      mode: mode || 'bd',
      entity: mode === 'grant' ? 'EAF' : 'FP',
      beachhead: 'BH1',
      strategic_rationale: 'Fallback single-target from theme sweep',
