      urgency: 'MEDIUM',
      constraint_flags: [],
      revenue_type: 'consulting',
      first_action: 'Research and validate source'
    }]
  };
}

// Stamp each opportunity with routing metadata for downstream nodes
const stamped = discoveryResult.opportunities.map((opp, i) => ({
  ...opp,
  discovery_rank:     opp.rank || i + 1,
  sourceLabel:        `Strategic: ${opp.opportunity_target ? opp.opportunity_target.substring(0, 60) : theme_primary}`,
  isScheduled:        true,
  strategic_sweep:    true,
  theme_primary,
  theme_secondary,
  timestamp,
  parent_summary:     discoveryResult.strategic_summary,
  total_in_batch:     discoveryResult.opportunities.length,
}));

// Save discovery report
const reportPath = `/data/Aidan_Outputs/Scout/StrategicDiscovery_${new Date().toISOString().slice(0,10)}.json`;
try {
  fs.mkdirSync('/data/Aidan_Outputs/Scout', { recursive: true });
  fs.writeFileSync(reportPath, JSON.stringify({ timestamp, theme_primary, strategic_summary: discoveryResult.strategic_summary, opportunities: stamped }, null, 2), 'utf8');
} catch(e) {}

// Return array — SplitInBatches will iterate one item at a time
return stamped.map(opp => ({ json: opp }));

// Brave Search v6 — receives one opportunity target from Split Opportunities
// Uses opp.search_query if available (from Strategic Discovery), else falls back to opp.query
const https = require('https');
const input = $input.first().json;

// Support both strategic discovery output and direct single-query input
const query     = input.search_query || input.query || input.opportunity_target || '';
const mode      = input.mode || 'bd';
const grantName = input.grantName || null;
const sourceLabel = input.sourceLabel || 'Scout v6';
const isScheduled = input.isScheduled || false;
const timestamp   = input.timestamp   || new Date().toISOString();

const BRAVE_API_KEY = $env.BRAVE_API_KEY || '';
const encodedQuery = encodeURIComponent(query);
const path = `/res/v1/web/search?q=${encodedQuery}&count=5&search_lang=en&country=us&text_decorations=false&extra_snippets=true`;
const options = {
  hostname: 'api.search.brave.com', port: 443, path, method: 'GET',
  headers: { 'Accept': 'application/json', 'X-Subscription-Token': BRAVE_API_KEY }
};
const rawResponse = await new Promise((resolve, reject) => {
  const req = https.request(options, (res) => {
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => resolve({ status: res.statusCode, body: Buffer.concat(chunks).toString() }));
  });
  req.on('error', reject);
  req.end();
});
let braveResults = [];
let braveError = null;
if (rawResponse.status === 200) {
  try {
    const parsed = JSON.parse(rawResponse.body);
    const webResults = parsed?.web?.results || [];
    braveResults = webResults.slice(0, 5).map((r, i) => ({
      index: i + 1, title: r.title || '', url: r.url || '',
      description: r.description || '',
      extra_snippets: (r.extra_snippets || []).slice(0, 2)
    }));
  } catch(e) { braveError = 'Failed to parse Brave response: ' + e.message; }
} else {
  braveError = `Brave API returned status ${rawResponse.status}: ${rawResponse.body.substring(0, 200)}`;
}
let braveContext = '';
if (braveResults.length > 0) {
  braveContext = braveResults.map(r => {
    const snippets = r.extra_snippets.length > 0 ? r.extra_snippets.join(' ') : '';
    return `[${r.index}] ${r.title}\nURL: ${r.url}\nSummary: ${r.description}\n${snippets ? 'Detail: ' + snippets : ''}`;
  }).join('\n\n');
} else {
  braveContext = braveError || 'No results returned from Brave Search.';
}
const fetchUrls = braveResults.slice(0, 2).map(r => r.url).filter(u => u.length > 0);
return [{ json: { ...input, mode, query, grantName, sourceLabel, isScheduled, timestamp, braveContext, braveResults, fetchUrls, braveError } }];

const https = require('https');
const http = require('http');
const { mode, query, grantName, sourceLabel, isScheduled, timestamp, braveContext, braveResults, fetchUrls, braveError } = $input.first().json;
const WORD_THRESHOLD = 500;
const FETCH_TIMEOUT_MS = 8000;
const MAX_CONTENT_CHARS = 8000;
function fetchUrl(url) {
  return new Promise((resolve) => {
    const timer = setTimeout(() => resolve({ ok: false, reason: 'timeout', content: '' }), FETCH_TIMEOUT_MS);
    try {
      const lib = url.startsWith('https') ? https : http;
      const req = lib.get(url, { headers: { 'User-Agent': 'Mozilla/5.0 (compatible; KAI-Netics-Scout/6.0)' } }, (res) => {
        if ((res.statusCode === 301 || res.statusCode === 302) && res.headers.location) { clearTimeout(timer); fetchUrl(res.headers.location).then(resolve); return; }
        if (res.statusCode !== 200) { clearTimeout(timer); resolve({ ok: false, reason: `HTTP ${res.statusCode}`, content: '' }); return; }
        const chunks = [];
        res.on('data', c => chunks.push(c));
        res.on('end', () => {
          clearTimeout(timer);
          let text = Buffer.concat(chunks).toString('utf8', 0, 60000);
          text = text.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<style[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/\s{3,}/g, '\n\n').trim();
          resolve({ ok: true, content: text.substring(0, MAX_CONTENT_CHARS) });
        });
      });
      req.on('error', (e) => { clearTimeout(timer); resolve({ ok: false, reason: e.message, content: '' }); });
    } catch(e) { clearTimeout(timer); resolve({ ok: false, reason: e.message, content: '' }); }
  });
}
function wordCount(text) { return text.split(/\s+/).filter(w => w.length > 0).length; }
const fetchPromises = (fetchUrls || []).slice(0, 2).map(url => fetchUrl(url).then(result => ({ url, ...result })));
const fetchResults = await Promise.all(fetchPromises);
let enrichedContext = '';
const fetchSummary = [];
for (const result of fetchResults) {
  const wc = wordCount(result.content || '');
  if (result.ok && wc >= WORD_THRESHOLD) {
    enrichedContext += `\n\n=== FULL PAGE CONTENT: ${result.url} ===\n${result.content}\n`;
    fetchSummary.push(`FULL CONTENT (${wc} words): ${result.url}`);
  } else {
    const reason = !result.ok ? result.reason : `only ${wc} words`;
    enrichedContext += `\n\n=== PARTIAL/UNAVAILABLE: ${result.url} ===\n[Full content unavailable: ${reason}.]\n`;
    fetchSummary.push(`SNIPPET FALLBACK (${reason}): ${result.url}`);
  }
}
const combinedContext = ['=== LIVE BRAVE SEARCH RESULTS ===', braveContext || 'No Brave results available.', enrichedContext || ''].join('\n');
return [{ json: { ...$input.first().json, combinedContext, fetchSummary } }];

// SCOUT BRAIN v6 -- BD ANALYST MODE
// Unchanged from original. Receives one opportunity at a time from the split loop.
// strategic_rationale and first_action from Strategic Discovery are injected into
// the user prompt as additional context to improve extraction quality.
