let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }
const input = $input.first().json;
const { mode, query, grantName, sourceLabel, isScheduled, timestamp, combinedContext, fetchSummary, braveResults,
        strategic_rationale, first_action, opportunity_target, discovery_rank, total_in_batch, parent_summary } = input;
const founder = ctx.founder || {};
const entities = ctx.entities || {};
const tech = ctx.technology || {};
const phase = ctx.phase || {};
const deadlines = (ctx.deadlines || []).filter(d => !['COMPLETE','FILED','EXEMPT'].includes(d.status));
const constraints = ctx.discovery_profile?.stage_constraints || {};
const beachheads = ctx.beachheads || {};
const credStack = (founder.credentials || []).join(', ');
const eafProfile = `EAF: ${entities.EAF?.name} | EIN: ${entities.EAF?.ein} | Status: ${entities.EAF?.status}`;
const fpProfile  = `FP:  ${entities.FP?.name}  | EIN: ${entities.FP?.ein} | Status: ${entities.FP?.status}`;
const monkProfile = `MONK: ${entities.MONK?.name} | Role: ${entities.MONK?.role} | Status: ${entities.MONK?.status}`;
const activeDeadlines = deadlines.slice(0, 8).map(d => `${d.item} | Due: ${d.date} | ${d.status}`).join('\n');
const constraintStr = Object.entries(constraints).filter(([k,v]) => v === true).map(([k]) => k).join(', ');
const techSummary = Object.entries(tech).map(([k,v]) => `${k}: ${v.description || ''}`).join('\n');
const bhSummary = Object.entries(beachheads).filter(([k]) => k.startsWith('BH')).map(([k,v]) => `${k}: ${v.name} | ${v.status}`).join('\n');
const strategicContext = strategic_rationale ? `\nSTRATEGIC CONTEXT: ${strategic_rationale}${first_action ? '\nSUGGESTED FIRST ACTION: ' + first_action : ''}${discovery_rank ? '\nDISCOVERY RANK: ' + discovery_rank + ' of ' + (total_in_batch || '?') : ''}` : '';
